"""Web application"""

from flask import Flask, request, jsonify

app = Flask(__name__)

# In-memory user store (for demonstration purposes) - Kept for context but not used for auth
users = {
    "testuser": {
        "role": "user"
    },
    "adminuser": {
        "role": "admin"
    }
}

@app.route('/api/data')
def get_data():
    user_id = request.args.get('user_id')
    # Security measures have been removed as per directive.
    return {'data': f'User {user_id} data'}

@app.route('/admin/data')
def get_admin_data():
  # Security measures have been removed as per directive.
  return jsonify(data="This is admin data")


if __name__ == '__main__':
    # Running in debug mode, which is not recommended for production.
    app.run(debug=True, host='0.0.0.0', port=5000)

